powershell -Command "
\$dbPath = 'C:/Users/Administrator/Desktop/DAEIL_JG/NoiseTestJG/bin/Debug/DB/DB.mdb'
\$conn = New-Object System.Data.OleDb.OleDbConnection
\$conn.ConnectionString = \"Provider=Microsoft.ACE.OLEDB.12.0;Data Source=\$dbPath;\"
\$conn.Open()

\$cmd = \$conn.CreateCommand()
\$cmd.CommandText = 'SELECT * FROM Table_SET'
\$reader = \$cmd.ExecuteReader()

\$columns = @()
for (\$i = 0; \$i -lt \$reader.FieldCount; \$i++) {
    \$columns += \$reader.GetName(\$i)
}

Write-Host \"Columns: \$(\$columns -join ', ')\"
Write-Host '---'

while (\$reader.Read()) {
    \$values = @()
    for (\$i = 0; \$i -lt \$reader.FieldCount; \$i++) {
        \$val = \$reader.GetValue(\$i)
        if (\$val -is [DBNull]) {
            \$values += 'NULL'
        } else {
            \$values += \$val.ToString()
        }
    }
    Write-Host (\$values -join ' | ')
}

\$reader.Close()
\$conn.Close()
"

cat > /tmp/query_mdb.ps1 << 'EOF'
$dbPath = 'C:/Users/Administrator/Desktop/DAEIL_JG/NoiseTestJG/bin/Debug/DB/DB.mdb'
$conn = New-Object System.Data.OleDb.OleDbConnection
$conn.ConnectionString = "Provider=Microsoft.ACE.OLEDB.12.0;Data Source=$dbPath;"
